import{_ as t,a,b as n,c as o,d as i}from"./chunks/复制刷新令牌.IwW3dosg.js";import{_ as r,o as d,c as l,a2 as s}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"Een OneDrive-kanaal toevoegen","description":"","frontmatter":{},"headers":[],"relativePath":"nl-NL/upload/onedrive.md","filePath":"nl-NL/upload/onedrive.md","lastUpdated":1781962217000}'),p={name:"nl-NL/upload/onedrive.md"};function c(h,e,g,u,b,k){return d(),l("div",null,[...e[0]||(e[0]=[s('<h1 id="een-onedrive-kanaal-toevoegen" tabindex="-1">Een OneDrive-kanaal toevoegen <a class="header-anchor" href="#een-onedrive-kanaal-toevoegen" aria-label="Permalink to &quot;Een OneDrive-kanaal toevoegen&quot;">​</a></h1><h2 id="wat-je-vooraf-nodig-hebt" tabindex="-1">Wat je vooraf nodig hebt <a class="header-anchor" href="#wat-je-vooraf-nodig-hebt" aria-label="Permalink to &quot;Wat je vooraf nodig hebt&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Vereiste</th><th>Waarom je dit nodig hebt</th></tr></thead><tbody><tr><td>Microsoft-account</td><td>Voor toegang tot Microsoft-beheerpagina&#39;s en autorisatie van OneDrive</td></tr><tr><td>Je ImgBed-domein</td><td>Voor de OAuth-callback-URL</td></tr><tr><td>Appregistratie</td><td>Voor het genereren van <code>Client ID</code> en <code>Client Secret</code></td></tr><tr><td>OneDrive-account</td><td>De daadwerkelijke opslaglocatie voor bestanden</td></tr></tbody></table><h2 id="instellen" tabindex="-1">Instellen <a class="header-anchor" href="#instellen" aria-label="Permalink to &quot;Instellen&quot;">​</a></h2><h3 id="stap-1-open-microsoft-entra-id" tabindex="-1">Stap 1: Open Microsoft Entra ID <a class="header-anchor" href="#stap-1-open-microsoft-entra-id" aria-label="Permalink to &quot;Stap 1: Open Microsoft Entra ID&quot;">​</a></h3><ol><li>Open <code>portal.azure.com</code>.</li><li>Zoek bovenaan naar <code>Microsoft Entra ID</code>.</li><li>Staat de doelpagina niet in de lijst, kies dan:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Continue searching in Microsoft Entra ID</span></span></code></pre></div><ol start="4"><li>Open <code>Microsoft Entra ID</code>.</li><li>Open <code>App registrations</code>.</li><li>Klik op <code>New registration</code>.</li></ol><h3 id="stap-2-registreer-een-app" tabindex="-1">Stap 2: Registreer een app <a class="header-anchor" href="#stap-2-registreer-een-app" aria-label="Permalink to &quot;Stap 2: Registreer een app&quot;">​</a></h3><p>Vul op de pagina <code>New registration</code> het volgende in:</p><table tabindex="0"><thead><tr><th>Veld</th><th>Wat je invult</th></tr></thead><tbody><tr><td>Name</td><td>Een herkenbare naam, bijvoorbeeld <code>imgbed-onedrive</code></td></tr><tr><td>Supported account types</td><td>Kies op basis van de tabel hieronder</td></tr><tr><td>Redirect URI type</td><td><code>Web</code></td></tr><tr><td>Redirect URI</td><td><code>https://your-domain.com/api/oauth/onedrive/callback</code></td></tr></tbody></table><p>Richtlijn voor accounttype:</p><table tabindex="0"><thead><tr><th>Situatie</th><th>Supported Account Types</th></tr></thead><tbody><tr><td>Alleen persoonlijke OneDrive</td><td>Kies de optie voor persoonlijke Microsoft-accounts.</td></tr><tr><td>Persoonlijke en werk-/schoolaccounts</td><td>Kies de optie die persoonlijke en organisatieaccounts ondersteunt.</td></tr><tr><td>Alleen zakelijke of school-OneDrive</td><td>Kies de optie voor organisatieaccounts.</td></tr></tbody></table><p>Klik na het invullen op registreren.</p><p><img src="'+t+'" alt="OneDrive-app maken" loading="lazy"></p><h3 id="stap-3-kopieer-appgegevens" tabindex="-1">Stap 3: Kopieer appgegevens <a class="header-anchor" href="#stap-3-kopieer-appgegevens" aria-label="Permalink to &quot;Stap 3: Kopieer appgegevens&quot;">​</a></h3><p>Kopieer na het aanmaken deze waarden van de overzichtspagina:</p><table tabindex="0"><thead><tr><th>Microsoft-veld</th><th>ImgBed-veld</th></tr></thead><tbody><tr><td><code>Application (client) ID</code></td><td><code>Client ID</code></td></tr><tr><td><code>Directory (tenant) ID</code></td><td><code>Tenant ID</code> voor organisatieaccounts</td></tr></tbody></table><p><img src="'+a+'" alt="Application- en tenant-ID" loading="lazy"></p><h3 id="stap-4-maak-een-client-secret" tabindex="-1">Stap 4: Maak een Client Secret <a class="header-anchor" href="#stap-4-maak-een-client-secret" aria-label="Permalink to &quot;Stap 4: Maak een Client Secret&quot;">​</a></h3><ol><li>Open <code>Certificates &amp; secrets</code>.</li><li>Klik op <code>New client secret</code>.</li><li>Vul een herkenbare omschrijving in.</li><li>Kies een verloopperiode.</li><li>Kopieer de <code>Value</code> direct nadat deze is aangemaakt.</li></ol><p><img src="'+n+'" alt="Client Secret Value bewaren" loading="lazy"></p><h3 id="stap-5-voeg-api-rechten-toe" tabindex="-1">Stap 5: Voeg API-rechten toe <a class="header-anchor" href="#stap-5-voeg-api-rechten-toe" aria-label="Permalink to &quot;Stap 5: Voeg API-rechten toe&quot;">​</a></h3><ol><li>Open <code>API permissions</code>.</li><li>Klik op <code>Add a permission</code>.</li><li>Kies <code>Microsoft Graph</code>.</li><li>Kies <code>Delegated permissions</code>.</li><li>Voeg deze rechten toe:</li></ol><table tabindex="0"><thead><tr><th>Recht</th><th>Doel</th></tr></thead><tbody><tr><td><code>Files.ReadWrite.All</code></td><td>Bestanden uploaden, mappen maken en bestanden verwijderen</td></tr><tr><td><code>offline_access</code></td><td>Laat ImgBed een <code>Refresh Token</code> ophalen</td></tr><tr><td><code>User.Read</code></td><td>Leest account- en quotainformatie</td></tr></tbody></table><h3 id="stap-6-vul-het-onedrive-kanaal-in" tabindex="-1">Stap 6: Vul het OneDrive-kanaal in <a class="header-anchor" href="#stap-6-vul-het-onedrive-kanaal-in" aria-label="Permalink to &quot;Stap 6: Vul het OneDrive-kanaal in&quot;">​</a></h3><p>Kies in Uploadinstellingen <code>OneDrive</code> en vul in:</p><table tabindex="0"><thead><tr><th>ImgBed-veld</th><th>Wat je invult</th></tr></thead><tbody><tr><td>Kanaalnaam</td><td>Een herkenbare naam, bijvoorbeeld <code>Main OneDrive</code></td></tr><tr><td>Client ID</td><td>De Microsoft <code>Application (client) ID</code></td></tr><tr><td>Client Secret</td><td>De gekopieerde <code>Client Secret Value</code></td></tr><tr><td>Tenant ID</td><td>Gebruik de tabel hieronder</td></tr><tr><td>Refresh Token</td><td>Laat voorlopig leeg</td></tr><tr><td>Hoofdmap</td><td>Optioneel. Standaard <code>imgbed</code>.</td></tr><tr><td>Notitie</td><td>Optioneel</td></tr></tbody></table><p><img src="'+o+'" alt="OneDrive-kanaalconfiguratie invullen" loading="lazy"></p><p>Zo vul je <code>Tenant ID</code> in:</p><table tabindex="0"><thead><tr><th>Gekozen accounttype</th><th>ImgBed <code>Tenant ID</code></th></tr></thead><tbody><tr><td>Persoonlijke accounts</td><td><code>consumers</code></td></tr><tr><td>Persoonlijke en organisatieaccounts</td><td><code>common</code></td></tr><tr><td>Alleen huidige organisatie</td><td>De <code>Directory (tenant) ID</code></td></tr></tbody></table><h3 id="stap-7-haal-het-refresh-token-op" tabindex="-1">Stap 7: Haal het Refresh Token op <a class="header-anchor" href="#stap-7-haal-het-refresh-token-op" aria-label="Permalink to &quot;Stap 7: Haal het Refresh Token op&quot;">​</a></h3><ol><li>Klik in ImgBed op <code>Get Token</code>.</li><li>Meld je aan met het Microsoft-account dat je wilt koppelen.</li><li>Keur de autorisatie goed.</li><li>De callbackpagina toont een <code>Refresh Token</code>.</li><li>Kopieer het.</li><li>Ga terug naar ImgBed en plak het in het veld <code>Refresh Token</code>.</li></ol><p><img src="'+i+`" alt="Refresh Token kopiëren" loading="lazy"></p><h3 id="stap-8-sla-het-kanaal-op" tabindex="-1">Stap 8: Sla het kanaal op <a class="header-anchor" href="#stap-8-sla-het-kanaal-op" aria-label="Permalink to &quot;Stap 8: Sla het kanaal op&quot;">​</a></h3><p>Sla het kanaal op zodra alle velden zijn ingevuld.</p><h2 id="snelle-flow" tabindex="-1">Snelle flow <a class="header-anchor" href="#snelle-flow" aria-label="Permalink to &quot;Snelle flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Open portal.azure.com</span></span>
<span class="line"><span>-&gt; Zoek Microsoft Entra ID</span></span>
<span class="line"><span>-&gt; Open App registrations</span></span>
<span class="line"><span>-&gt; Registreer een nieuwe app</span></span>
<span class="line"><span>-&gt; Vul Name / Supported account types / Web redirect URI in</span></span>
<span class="line"><span>-&gt; Registreer</span></span>
<span class="line"><span>-&gt; Kopieer Application (client) ID</span></span>
<span class="line"><span>-&gt; Controleer de callback-URL bij Authentication</span></span>
<span class="line"><span>-&gt; Maak een Client Secret in Certificates &amp; secrets</span></span>
<span class="line"><span>-&gt; Voeg rechten toe bij API permissions</span></span>
<span class="line"><span>-&gt; Vul Client ID / Client Secret / Tenant ID in ImgBed in</span></span>
<span class="line"><span>-&gt; Klik Get Token</span></span>
<span class="line"><span>-&gt; Kopieer het Refresh Token van de callbackpagina</span></span>
<span class="line"><span>-&gt; Plak het in ImgBed en sla op</span></span></code></pre></div><h2 id="referenties" tabindex="-1">Referenties <a class="header-anchor" href="#referenties" aria-label="Permalink to &quot;Referenties&quot;">​</a></h2><ol><li>Microsoft Entra appregistratie: <a href="https://learn.microsoft.com/en-us/entra/identity-platform/quickstart-register-app" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/entra/identity-platform/quickstart-register-app</a></li><li>Microsoft identity platform authorization code flow: <a href="https://learn.microsoft.com/en-us/entra/identity-platform/v2-oauth2-auth-code-flow" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/entra/identity-platform/v2-oauth2-auth-code-flow</a></li><li>Microsoft Graph user authentication: <a href="https://learn.microsoft.com/en-us/graph/auth-v2-user" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/graph/auth-v2-user</a></li></ol>`,40)])])}const D=r(p,[["render",c]]);export{v as __pageData,D as default};
